agent1_plan:
{
  "user_query": "Compare Microsoft against enterprise software peers — Salesforce, Adobe, ServiceNow, and Oracle — from 2017 to 2021. Who had the best return and who had the best risk-adjusted performance?",
  "intent": "single_stock_deep_dive",
  "tickers_or_sectors": [
    "MSFT",
    "CRM",
    "ADBE",
    "NOW",
    "ORCL"
  ],
  "time_window": {
    "start": "2017-01",
    "end": "2021-12",
    "note": "Full available dataset window (monthly data from Jan 2017 through Dec 2021). Use entire period requested by user and fully covered by the CSVs."
  },
  "quantitative_questions": [
    "Calculate total cumulative return for each ticker from 2017-01 to 2021-12 (using price series or monthly returns). Rank tickers by total return.",
    "Compute annualized return and annualized volatility (standard deviation) for each ticker over the period (monthly returns → annualize).",
    "Compute risk-adjusted performance: Sharpe ratio for each ticker over the period assuming 0% risk-free rate (use monthly returns, annualize by sqrt(12)). Rank tickers by Sharpe.",
    "Compute maximum drawdown for each ticker over the period and report peak-to-trough dates and drawdown magnitude.",
    "Produce a pairwise correlation matrix of monthly returns among the five tickers for the full period."
  ],
  "qualitative_questions": [
    "What product, business-model or go-to-market changes (cloud migrations, subscription shifts, major acquisitions) explain differential performance among MSFT, CRM, ADBE, NOW and ORCL during 2017–2021?",
    "Which macro or industry factors (enterprise cloud spending, digital transformation, competitive shifts) most influenced enterprise software returns over 2017–2021?"
  ],
  "chart_requests": [
    {
      "chart_id": "cumulative_normalized_price",
      "chart_type": "line",
      "description": "Plot normalized price paths for MSFT, CRM, ADBE, NOW, ORCL from 2017-01 to 2021-12. Normalize each ticker to 100 at 2017-01 and plot monthly values on one chart with legend and dates on x-axis."
    },
    {
      "chart_id": "cumulative_return_from_returns",
      "chart_type": "line",
      "description": "Plot cumulative return computed from monthly returns (product of 1+monthly_return) for each ticker across the full period. Show percent on y-axis and time on x-axis."
    },
    {
      "chart_id": "annualized_return_vs_volatility",
      "chart_type": "scatter",
      "description": "Scatter chart with annualized volatility (x-axis) vs annualized return (y-axis) for each ticker. Label points with ticker symbols and include iso-Sharpe lines (optional) to visualize risk-adjusted positions."
    },
    {
      "chart_id": "rolling_12m_return_and_vol",
      "chart_type": "line",
      "description": "Two-panel plot: top panel = rolling 12-month cumulative return for each ticker; bottom panel = rolling 12-month annualized volatility for each ticker. Use monthly step and include legend."
    },
    {
      "chart_id": "max_drawdown_comparison",
      "chart_type": "bar",
      "description": "Bar chart showing maximum drawdown (percentage) for each ticker over the full period. Annotate bars with peak and trough dates for each drawdown."
    }
  ],
  "presentation_angle": "Deliver a focused comparison that identifies which of MSFT, CRM, ADBE, NOW and ORCL delivered the highest total return and which delivered the highest risk-adjusted return (Sharpe) from 2017–2021, and contextualize findings with drawdown and correlation evidence.",
  "out_of_scope_notes": "Analysis limited to monthly prices/returns through 2021-12. Any explanations about causes (acquisitions, product strategy, regulatory impact, fundamentals) require external sources and are out of scope for the CSV-only quantitative analysis. The analyst should verify that each requested ticker exists in tickerlist.csv/returns.csv/prices.csv; if a ticker is missing or has incomplete data, report that and restrict calculations accordingly."
}
